namespace sv_2f3bcfcd03524f83b913f8b61112b3c6.Services;

public class WarehouseStateService
{
    private string _currentWarehouseId = "WH-001";

    public string CurrentWarehouseId => _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }

    public static IReadOnlyList<(string Id, string Name)> AvailableWarehouses { get; } =
    [
        ("WH-001", "Warehouse A — East"),
        ("WH-002", "Warehouse B — West"),
        ("WH-003", "Warehouse C — Central"),
    ];
}

namespace sv_2f3bcfcd03524f83b913f8b61112b3c6.Services;

public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private readonly Lock _lock = new();

    public int LatestLowStockCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulates a database query — returns a random number 0–15.
        return Task.FromResult(Random.Shared.Next(0, 16));
    }

    /// <summary>
    /// Called by components that want polling to run while they are active.
    /// Polling starts on the first subscriber and stops when all unsubscribe.
    /// </summary>
    public void Subscribe()
    {
        lock (_lock)
        {
            _subscriberCount++;
            if (_subscriberCount == 1) StartPolling();
        }
    }

    public void Unsubscribe()
    {
        lock (_lock)
        {
            _subscriberCount = Math.Max(0, _subscriberCount - 1);
            if (_subscriberCount == 0) StopPolling();
        }
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire an initial poll immediately.
        await RefreshAsync();

        while (!ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer!.WaitForNextTickAsync(ct)) break;
                await RefreshAsync();
            }
            catch (OperationCanceledException) { break; }
        }
    }

    private async Task RefreshAsync()
    {
        LatestLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async void HandleWarehouseChanged()
    {
        // Warehouse changed — refresh immediately so all subscribers update.
        await RefreshAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        StopPolling();
    }
}

