+            Low-stock alerts:
+            <span class="badge @(_count > 0 ? "bg-danger" : "bg-success") fs-6">@_count</span>
+        </p>
+        <p class="text-muted small mb-0">Refreshes every 10 seconds. Last update: @_lastRefresh.ToString("T")</p>
+    </div>
+</div>
+
+@code {
+    private int _count;
+    private DateTime _lastRefresh = DateTime.Now;
+
+    protected override void OnInitialized()
+    {
+        WarehouseState.OnChange += OnWarehouseChanged;
+        AlertService.OnAlertCountChanged += OnAlertChanged;
+
+        // Start polling while this page is active.
+        AlertService.Subscribe();
+    }
+
+    private void OnWarehouseChanged() => InvokeAsync(StateHasChanged);
+
+    private async Task OnAlertChanged()
+    {
+        _count = AlertService.LatestLowStockCount;
+        _lastRefresh = DateTime.Now;
+        await InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        WarehouseState.OnChange -= OnWarehouseChanged;
+        AlertService.OnAlertCountChanged -= OnAlertChanged;
+        AlertService.Unsubscribe();
+    }
+}
+

